// ====== 全局状态 ======
var currentPath = '/';
var historyStack = [];
var clipboard = { action: null, paths: [] };
var contextTarget = null;
var selectedFiles = new Set();
var selectedPaths = new Set();
var touchTimer = null;
var editor;
var currentEditPath = '';
var pendingFiles = []; 
var currentConflicts = [];
var batchOverwriteResolver = null;
var currentRenamePath = '';
var globalFavorites = [];
var trashEnabled = true; // 回收站状态，默认开启

// ====== 初始化 ======
document.addEventListener('DOMContentLoaded', function() {
    // 从 URL Hash 中恢复上次的路径，解决刷新丢失目录的问题
    var initialPath = '/';
    if (window.location.hash) {
        var hashPath = decodeURIComponent(window.location.hash.substring(1));
        if (hashPath) {
            initialPath = hashPath;
        }
    }
    loadFileList(initialPath);
    checkSSHStatus();
    loadDiskUsage();
    loadFavorites();
    bindGlobalEvents();
    initDropZone();
});

// 监听浏览器的前进/后退按钮
window.addEventListener('hashchange', function() {
    var newPath = decodeURIComponent(window.location.hash.substring(1)) || '/';
    if (fixPath(newPath) !== fixPath(currentPath)) {
        loadFileList(newPath);
    }
});

// 路径修复
function fixPath(path) {
    if (!path) return '/';
    return path.replace(/\/+/g, '/');
}

// 格式化大小
function formatSize(bytes) {
    if (!bytes) return '0 B';
    var gb = (bytes / 1073741824).toFixed(1);
    return gb + ' GB';
}

// 加载磁盘使用情况
function loadDiskUsage() {
    var xhr = new XMLHttpRequest();
    xhr.open('GET', '/api/system/disk?path=/', true);
    xhr.onreadystatechange = function() {
        if (xhr.readyState === 4 && xhr.status === 200) {
            try {
                var data = JSON.parse(xhr.responseText);
                var diskInfoEl = document.getElementById('diskInfo');
                if (!diskInfoEl) return;
                if (data.success && data.info) {
                    var info = data.info;
                    diskInfoEl.innerHTML = 
                        '总计: <strong>' + formatSize(info.total) + '</strong> | ' +
                        '已用: <strong style="color:#ff4d4f;">' + formatSize(info.used) + ' (' + info.percent + ')</strong> | ' +
                        '可用: <strong style="color:#20a53a;">' + formatSize(info.available) + '</strong>';
                } else {
                    diskInfoEl.textContent = '磁盘信息获取失败';
                }
            } catch(e) {
                diskInfoEl.textContent = '磁盘信息解析异常';
            }
        }
    };
    xhr.send();
}

// ====== 收藏夹功能 (云端同步) ======
async function loadFavorites() {
    try {
        var resp = await fetch('/api/favorites');
        var data = await resp.json();
        if (data.success) {
            globalFavorites = data.favorites || [];
        }
    } catch(e) {}
}

function isFavorited(path) {
    return globalFavorites.includes(path);
}

function saveFavoritesToServer() {
    fetch('/api/favorites', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({favorites: globalFavorites})
    });
}

function toggleFavorites(e) {
    if(e) e.stopPropagation();
    var dropdown = document.getElementById('favoritesDropdown');
    if (dropdown.classList.contains('hidden')) {
        renderFavoritesDropdown();
        var rect = e.target.getBoundingClientRect();
        dropdown.style.top = (rect.bottom + 18) + 'px';
        dropdown.style.left = rect.left + 'px';
        dropdown.classList.remove('hidden');
    } else {
        dropdown.classList.add('hidden');
    }
}

function renderFavoritesDropdown() {
    var dropdown = document.getElementById('favoritesDropdown');
    if (globalFavorites.length === 0) {
        dropdown.innerHTML = '<div class="fav-item" style="color:#999; cursor:default;">暂无收藏</div>';
        return;
    }
    var html = '';
    globalFavorites.forEach(function(p) {
        html += '<div class="fav-item" onclick="loadFileList(\'' + p + '\'); toggleFavorites();">' + p + '</div>';
    });
    dropdown.innerHTML = html;
}

// ====== 文件列表 ======
function loadFileList(path) {
    currentPath = fixPath(path);
    
    // 将当前路径同步到 URL Hash 中，方便刷新保持和分享链接
    var newHash = '#' + encodeURIComponent(currentPath);
    if (window.location.hash !== newHash) {
        window.location.hash = newHash;
    }
    
    var pathInput = document.getElementById('pathInput');
    if (pathInput) pathInput.value = currentPath;
    
    var tbody = document.getElementById('fileTableBody');
    if (!tbody) return;
    
    tbody.innerHTML = '<tr><td colspan="6" class="loading">加载中...</td></tr>';

    fetch('/api/files/list?path=' + encodeURIComponent(currentPath))
        .then(function(resp) { return resp.json(); })
        .then(function(data) {
            if (data.success) {
                renderFileList(data);
                renderBreadcrumb(currentPath);
                updateStatus((data.dir_count || 0) + ' 个目录, ' + (data.file_count || 0) + ' 个文件');
            } else {
                tbody.innerHTML = '<tr><td colspan="6" class="loading" style="color:red">' + data.msg + '</td></tr>';
            }
        })
                .catch(function(err) {
            tbody.innerHTML = '<tr><td colspan="6" class="loading" style="color:red">文件管理器已停止, 请重启!</td></tr>';
            document.getElementById('sshStatus').textContent = 'SSH: 服务已断开';
            document.getElementById('sshStatus').classList.add('disconnected');
        });
}

function renderFileList(data) {
    var tbody = document.getElementById('fileTableBody');
    if (!tbody) return;
    
    tbody.innerHTML = '';
    var fragment = document.createDocumentFragment();

    if (currentPath !== '/') {
        var backTr = document.createElement('tr');
        backTr.style.cursor = 'pointer';
        backTr.innerHTML = '<td></td><td><span class="file-icon">📁</span><span class="dir-name">..</span></td><td>-</td><td>-</td><td>-</td><td></td>';
        backTr.onclick = function() { goBack(); };
        fragment.appendChild(backTr);
    }

    if (data.files.length === 0) {
        var emptyTr = document.createElement('tr');
        emptyTr.innerHTML = '<td colspan="6" class="loading">文件夹中没有文件</td>';
        fragment.appendChild(emptyTr);
    } else {
        data.files.forEach(function(file) {
            var fullPath = fixPath(currentPath + '/' + file.filename);
            var icon = getFileIcon(file);
            var tr = document.createElement('tr');
            tr.setAttribute('data-path', fullPath);
            tr.setAttribute('data-name', file.filename);
            tr.setAttribute('data-isDir', file.is_dir);
            tr.setAttribute('data-ext', file.extension);

            tr.addEventListener('click', function(e) {
                if (e.target.closest('.action-btn') || e.target.tagName === 'INPUT') return;
                selectRow(tr);
                handleItemClick(file, fullPath);
            });

            tr.addEventListener('contextmenu', function(e) {
                e.preventDefault();
                e.stopPropagation();
                selectRow(tr);
                contextTarget = fullPath;
                showContextMenu(e.clientX, e.clientY, file);
            });

            var touchStartX = 0, touchStartY = 0;
            tr.addEventListener('touchstart', function(e) {
                if (e.target.closest('.action-btn') || e.target.tagName === 'INPUT') return;
                touchStartX = e.touches[0].clientX;
                touchStartY = e.touches[0].clientY;
                touchTimer = setTimeout(function() {
                    e.preventDefault();
                    selectRow(tr);
                    contextTarget = fullPath;
                    showContextMenu(touchStartX, touchStartY, file);
                }, 500);
            }, { passive: false });

            tr.addEventListener('touchend', function(e) { clearTimeout(touchTimer); });
            tr.addEventListener('touchmove', function(e) { clearTimeout(touchTimer); });

            var actionsHtml = '';
            if (!file.is_dir) {
                actionsHtml += '<button class="action-btn" onclick="event.stopPropagation();editFile(\'' + fullPath + '\')">编辑</button>';
                actionsHtml += '<button class="action-btn" onclick="event.stopPropagation();downloadFile(\'' + fullPath + '\')">下载</button>';
            }
            actionsHtml += '<button class="action-btn danger" onclick="event.stopPropagation();deleteFile(\'' + fullPath + '\')">删除</button>';

            tr.innerHTML = '<td class="col-checkbox"></td>' +
                '<td class="col-name"><span class="file-icon">' + icon + '</span><span class="' + (file.is_dir ? 'dir-name' : 'file-name') + '">' + file.filename + '</span></td>' +
                '<td class="col-size">' + (file.is_dir ? '-' : file.size_str) + '</td>' +
                '<td class="col-time">' + file.mtime_str + '</td>' +
                '<td class="col-perms">' + file.permissions + '</td>' +
                '<td class="col-actions">' + actionsHtml + '</td>';
            
            var checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.onchange = function(e) { 
                e.stopPropagation();
                toggleSelect(this, file.filename, fullPath);
            };
            var tdCheckbox = tr.querySelector('.col-checkbox');
            if (tdCheckbox) tdCheckbox.appendChild(checkbox);
            
            fragment.appendChild(tr);
        });
    }
    
    tbody.appendChild(fragment);
    
    selectedFiles.clear();
    selectedPaths.clear();
    updateBatchOps();
}

var imgExts = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'svg'];

function handleItemClick(file, fullPath) {
    if (file.is_dir) {
        historyStack.push(currentPath);
        loadFileList(fullPath);
    } else {
        var exts = ['zip', 'tar', 'gz', 'tgz', 'rar', '7z'];
        if (exts.indexOf(file.extension) !== -1) {
            showConfirmModal('确认解压', '是否将 ' + file.filename + ' 解压到当前目录的同名文件夹中？').then(function(confirmed) {
                if (confirmed) {
                    extractFile(fullPath);
                }
            });
        } else if (imgExts.indexOf(file.extension) !== -1) {
            // 如果是图片，点击文件名查看预览
            showImagePreview(fullPath);
        } else {
            // 其他文件点击行直接编辑
            editFile(fullPath);
        }
    }
}

function showImagePreview(path) {
    var img = document.getElementById('previewImage');
    // 直接将 src 指向下载接口，浏览器自动流式加载，秒开
    img.src = '/api/files/download?path=' + encodeURIComponent(path);
    showModal('imagePreviewModal');
}

function selectRow(tr) {
    if (!tr) return;
    var rows = document.querySelectorAll('.file-table tbody tr');
    for (var i = 0; i < rows.length; i++) {
        rows[i].classList.remove('selected');
        var cb = rows[i].querySelector('input[type="checkbox"]');
        if (cb) cb.checked = false;
    }
    tr.classList.add('selected');
    var checkbox = tr.querySelector('input[type="checkbox"]');
    if (checkbox) checkbox.checked = true;
    
    selectedFiles.clear();
    selectedPaths.clear();
    var name = tr.getAttribute('data-name');
    var path = tr.getAttribute('data-path');
    if (name) selectedFiles.add(name);
    if (path) selectedPaths.add(path);
    updateBatchOps();
}

